  ('aboriginal-7fec267e-moex-00054', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-114-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '主管機關命甲履行某行政法上行為義務，並諭知若逾期未履行，將委託第三人依行政執行法規定 代為履行，其費用由甲負擔。甲逾期未履行該義務，主管機關即委託第三人代履行後，通知甲限 期繳納代履行費用。甲逾期未繳納，主管機關得為如何處理？', '["作成行政處分，限期命甲支付代履行費用", "提起一般給付訴訟，請求判命甲支付代履行費用", "移送法務部行政執行署所屬行政執行分署強制執行", "代位行使第三人之請求權，向民事法院提起給付訴訟，請求判命甲給付費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00055', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-114-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '下列何者非相當於訴願決定？', '["教師申訴評議委員會之再申訴決定", "會計師懲戒覆審委員會之決議", "公務人員保障暨培訓委員會之復審決定", "律師懲戒覆審委員會之決議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00056', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-114-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '關於撤銷原處分之訴願決定，其拘束力範圍，下列敘述何者正確？', '["僅訴願決定之法律見解對原處分機關有拘束力", "僅訴願決定之事實認定對原處分機關有拘束力", "訴願決定之法律見解與事實認定均對原處分機關有拘束力", "訴願決定對原處分機關不具拘束力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00057', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-114-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '關於都市計畫審查訴訟之敘述，下列何者正確？', '["都市計畫審查訴訟，專屬都市計畫區所在地之高等行政法院地方行政訴訟庭管轄", "得提起都市計畫審查訴訟者，以其權利受行政機關發布之違法都市計畫損害之人民為限", "都市計畫審查訴訟，原則上應於行政機關發布都市計畫後1年之不變期間內提起", "管轄之行政法院認為系爭都市計畫為違法者，原則上應作成宣告違法並向將來失效之形成判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00058', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-114-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '公平交易委員會審查化工事業甲與乙之結合案，雖作出不禁止決定，但附加負擔「應自結合起 5 年內每年執行動物保護慈善公益活動並提交報告」，甲僅對此附款不服，訴願未果後，應提起何種 訴訟？', '["撤銷訴訟", "一般給付之訴", "確認法律關係不存在之訴", "確認行政處分違法之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00059', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-114-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '關於國家賠償法之敘述，下列何者錯誤？', '["人民主張因違法行政處分而發生國家賠償訴訟時，經行政法院裁判確定該處分違法，普通法院 仍應審查是否具備其他賠償之要件", "管理機關對自然公物內之設施管理欠缺，致人民生命、身體或財產受損害者，構成國家賠償責任", "行政機關依國家賠償法為賠償後，得對實際應負最終賠償責任之機關求償", "國家賠償法所稱之行使公權力，係指公務員行使統治權作用之公法行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00060', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-114-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '下列何種情況應給予損失補償？', '["地方政府派員警驅趕閒置國有建築內長年聚集飲酒喧嘩之民眾，因衝突而違法使用警械致民眾 受傷", "消防車為搶救火災而駛入狹小巷弄，致路邊白線內側休旅車受損", "員警執行解散集會命令時，與集會民眾發生口角，員警憤而壓制民眾，造成民眾腦震盪住院治療", "颱風登陸前夕，地方政府於媒體中公告水門即將關閉，儘速移走堤防外之停車，民眾自信認為 不至於淹水而未移車，導致車輛泡水"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00061', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-113-adc7838e', 'sub-aboriginal-7fec267e-01', NULL, 'essay', '分別說明政策階段理論與政策反階段理論的意涵、基本命題、適用性，
